function Page() {
  const [users, setUsers] = useState(usersData);
  const [loading, setLoading] = useState(false);

  // Toggle suspend/activate
  const handleToggleStatus = (userId) => {
    const updatedUsers = users.map((user) =>
      user._id === userId
        ? {
            ...user,
            status: user.status === "ACTIVE" ? "SUSPENDED" : "ACTIVE",
          }
        : user
    );
    setUsers(updatedUsers);
  };

  return (
    <div className="overflow-x-auto rounded-lg shadow-sm mt-6">
      <table className="min-w-full bg-white border border-gray-200 rounded-lg">
        <thead className="bg-gray-50 text-sm text-gray-700">
          <tr>
            <th className="py-3 px-4 text-left font-semibold tracking-wide">
              Profile
            </th>
            <th className="py-3 px-4 text-left font-semibold tracking-wide">
              Username / Full Name
            </th>
            <th className="py-3 px-4 text-left font-semibold tracking-wide">
              Email
            </th>
            <th className="py-3 px-4 text-left font-semibold tracking-wide">
              Role
            </th>
            <th className="py-3 px-4 text-left font-semibold tracking-wide">
              Status
            </th>
            <th className="py-3 px-4 text-left font-semibold tracking-wide">
              Actions
            </th>
          </tr>
        </thead>

        <tbody className="text-sm text-gray-800">
          {users.map((user) => (
            <tr
              key={user._id}
              className="border-t border-gray-200 hover:bg-gray-100 transition-colors">
              <td className="py-3 px-4">
                <Image
                  src={user.image}
                  alt={user.username}
                  width={50}
                  height={50}
                  className="rounded-full object-cover border border-gray-300"
                />
              </td>

              <td className="py-3 px-4 font-medium text-[#7050ff]">
                <div>
                  <p>{user.username}</p>
                  <p className="text-gray-500 text-xs">
                    {user.firstName} {user.lastName}
                  </p>
                </div>
              </td>

              <td className="py-3 text-gray-600 px-4">{user.email}</td>
              <td className="py-3 text-gray-800 px-4">{user.role}</td>

              <td
                className={`py-3 px-4 font-semibold ${
                  user.status === "ACTIVE" ? "text-green-600" : "text-red-500"
                }`}>
                {user.status}
              </td>

              <td className="py-3 px-4">
                <button
                  onClick={() => handleToggleStatus(user._id)}
                  className={`px-3 py-1.5 text-sm rounded-md font-medium ${
                    user.status === "ACTIVE"
                      ? "bg-red-100 text-red-600 hover:bg-red-200"
                      : "bg-green-100 text-green-600 hover:bg-green-200"
                  }`}>
                  {user.status === "ACTIVE" ? "Suspend" : "Activate"}
                </button>
              </td>
            </tr>
          ))}
        </tbody>
      </table>
    </div>
  );
}

export default Page;
